.stage { position: relative; --x: 50%; --y: 50%; }
.copy-dim { color: rgba(255,255,255,0.1); }
.copy-lit { position: absolute; inset: 0; color: #fff;
  -webkit-mask-image: radial-gradient(circle 180px at var(--x) var(--y),
    #000 30%, transparent 78%);
  mask-image: radial-gradient(circle 180px at var(--x) var(--y),
    #000 30%, transparent 78%); }

var stage = document.querySelector(".stage");
stage.addEventListener("mousemove", function(e){
  var r = stage.getBoundingClientRect();
  stage.style.setProperty("--x", (e.clientX - r.left) + "px");
  stage.style.setProperty("--y", (e.clientY - r.top) + "px");
});
// 초기/터치 폴백 — 스테이지 중앙 좌표를 기본값으로 주입
stage.style.setProperty("--x", (stage.clientWidth / 2) + "px");
stage.style.setProperty("--y", (stage.clientHeight / 2) + "px");

