.lens { position: absolute; left: var(--x); top: var(--y);
  width: 180px; height: 180px;
  transform: translate(-50%, -50%); border-radius: 50%;
  background: url(artwork.jpg);  /* 원본과 같은 아트워크 */
  background-size: calc(var(--sw) * 2) calc(var(--sh) * 2);  /* 2배 */
  /* 역산: 렌즈 반경(90px) − 커서좌표 × 배율(2) */
  background-position: calc(90px - var(--x) * 2)
                       calc(90px - var(--y) * 2);
  background-repeat: no-repeat; }

