.glow-blob { position: absolute; left: 0; top: 0;
  border-radius: 50%; pointer-events: none; will-change: transform; }
.blob-a { width: 460px; height: 460px; filter: blur(70px);
  background: radial-gradient(closest-side,
    rgba(124,108,255,0.55), rgba(124,108,255,0.18) 55%, transparent 75%); }
.blob-b { width: 300px; height: 300px; filter: blur(50px);
  background: radial-gradient(closest-side,
    rgba(76,201,240,0.5), rgba(76,201,240,0.15) 55%, transparent 75%); }

var tx = 0, ty = 0, ax = 0, ay = 0, bx = 0, by = 0;
stage.addEventListener("mousemove", function(e){
  var r = stage.getBoundingClientRect();
  tx = e.clientX - r.left; ty = e.clientY - r.top;
});
function frame(){
  ax += (tx - ax) * 0.06; ay += (ty - ay) * 0.06;  // 느린 대형 blob
  bx += (tx - bx) * 0.12; by += (ty - by) * 0.12;  // 빠른 소형 blob
  blobA.style.transform = "translate(" + (ax - 230) + "px," + (ay - 230) + "px)";
  blobB.style.transform = "translate(" + (bx - 150) + "px," + (by - 150) + "px)";
  requestAnimationFrame(frame);
}
requestAnimationFrame(frame);

